import { useApproval } from "lib/hooks/useApproval";
import { useCallback } from "react";
import { useHasPendingApproval, useTransactionAdder } from "../state/transactions/hooks";
import { TransactionType } from "../state/transactions/types";
export { ApprovalState } from "lib/hooks/useApproval";
function useGetAndTrackApproval(getApproval) {
    const addTransaction = useTransactionAdder();
    return useCallback(()=>{
        return getApproval().then((pending)=>{
            if (pending) {
                const { response, tokenAddress, spenderAddress: spender, amount } = pending;
                addTransaction(response, {
                    type: TransactionType.APPROVAL,
                    tokenAddress,
                    spender,
                    amount: amount.quotient.toString()
                });
            }
        });
    }, [
        addTransaction,
        getApproval
    ]);
}
// returns a variable indicating the state of the approval and a function which approves if necessary or early returns
export function useApproveCallback(amountToApprove, spender) {
    const [approval, getApproval] = useApproval(amountToApprove, spender, useHasPendingApproval);
    return [
        approval,
        useGetAndTrackApproval(getApproval)
    ];
}
